.darma-loader-cssloaders-github-24 {
  display: inline-block;
  width: 128px;
  height: 8px;
  border-radius: 999px;
  background: color-mix(in srgb, var(--loader-color, #14b8a6) 16%, transparent);
  overflow: hidden;
}
.darma-loader-cssloaders-github-24::before {
      content: "";
      display: block;
      width: 42%;
      height: 100%;
      border-radius: inherit;
      background: linear-gradient(90deg, var(--loader-color, #14b8a6), var(--loader-secondary-color, #99f6e4));
      animation: darma-loader-cssloaders-github-24-progressSlide 0.9s ease-in-out infinite;
    }
    @keyframes darma-loader-cssloaders-github-24-progressSlide { 0% { transform: translateX(-120%); } 100% { transform: translateX(260%); } }

